// src/context/StudentProfileContext.jsx
import { createContext, useContext, useState, useEffect } from "react";
import { getStudentProfile } from "../api/auth";

const StudentProfileContext = createContext(null);

export const StudentProfileProvider = ({ children }) => {
  const [profile, setProfile]     = useState(null);
  const [loading, setLoading]     = useState(true);
  const [lastSaved, setLastSaved] = useState(null); // timestamp of last save

  // Fetch once on mount
  useEffect(() => {
    getStudentProfile()
      .then(p => setProfile(p))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  // Call this after a successful profile save to update context immediately
  const refreshProfile = async () => {
    try {
      const p = await getStudentProfile();
      setProfile(p);
      setLastSaved(Date.now());
    } catch (err) { console.error(err); }
  };

  // Update specific fields locally (instant UI update without re-fetch)
  const updateProfileField = (fields) => {
    setProfile(prev => prev ? { ...prev, ...fields } : fields);
    setLastSaved(Date.now());
  };

  return (
    <StudentProfileContext.Provider value={{
      profile, setProfile, loading,
      lastSaved, refreshProfile, updateProfileField,
    }}>
      {children}
    </StudentProfileContext.Provider>
  );
};

export const useStudentProfile = () => useContext(StudentProfileContext);
